import csv
import json
import xml.etree.ElementTree as ET
import os

def detect_file_format(file_path):
    try:
        with open(file_path, 'rb') as f:
            start = f.read(2048)
            try:
                snippet = start.decode('utf-8')
            except UnicodeDecodeError:
                return 'unknown'
            if snippet.strip() == '':
                return 'empty'
            if snippet.lstrip().startswith('{') or snippet.lstrip().startswith('['):
                return 'json'
            if snippet.lstrip().startswith('<?xml') or snippet.lstrip().startswith('<'):
                return 'xml'
            if ',' in snippet or '\t' in snippet or ';' in snippet:
                return 'csv'
            return 'unknown'
    except Exception:
        return 'unknown'

def parse_csv(file_path, encoding='utf-8'):
    data = []
    try:
        with open(file_path, encoding=encoding, newline='') as csvfile:
            # Detect delimiter
            sample = csvfile.read(2048)
            csvfile.seek(0)
            try:
                dialect = csv.Sniffer().sniff(sample)
            except Exception:
                dialect = csv.excel
            reader = csv.DictReader(csvfile, dialect=dialect)
            if not reader.fieldnames:
                raise ValueError("CSV file is missing headers")
            for row in reader:
                if any(row.values()):  # skip completely empty rows
                    data.append(row)
        if not data:
            raise ValueError("CSV file is empty or has no data rows")
        return data
    except Exception as e:
        raise ValueError(f"CSV parsing error: {e}")

def parse_json(file_path, encoding='utf-8'):
    try:
        with open(file_path, encoding=encoding) as jsonfile:
            content = jsonfile.read()
            if not content.strip():
                raise ValueError("JSON file is empty")
            data = json.loads(content)
            if isinstance(data, dict):
                if 'data' in data:
                    data = data['data']
            return data
    except Exception as e:
        raise ValueError(f"JSON parsing error: {e}")

def parse_xml(file_path, encoding='utf-8'):
    try:
        with open(file_path, encoding=encoding) as xmlfile:
            content = xmlfile.read()
            if not content.strip():
                raise ValueError("XML file is empty")
            root = ET.fromstring(content)
            data = []
            for child in root:
                row = {}
                for elem in child:
                    row[elem.tag] = elem.text
                if row:
                    data.append(row)
            if not data:
                # If root itself is a record
                row = {}
                for elem in root:
                    row[elem.tag] = elem.text
                if row:
                    data.append(row)
            if not data:
                raise ValueError("XML has no recognizable records")
            return data
    except Exception as e:
        raise ValueError(f"XML parsing error: {e}")

def convert_to_csv(data, file_path, encoding='utf-8'):
    try:
        if not data:
            raise ValueError("No data provided to write as CSV")
        with open(file_path, 'w', encoding=encoding, newline='') as csvfile:
            # For nested JSON, flatten each dictionary
            fieldnames = set()
            for item in data:
                if isinstance(item, dict):
                    fieldnames.update(flatten_dict(item).keys())
                else:
                    fieldnames.add(str(item))
            fieldnames = list(fieldnames)
            writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
            writer.writeheader()
            for item in data:
                if isinstance(item, dict):
                    writer.writerow(flatten_dict(item))
                else:
                    writer.writerow({str(item): item})
    except Exception as e:
        raise ValueError(f"CSV conversion error: {e}")

def convert_to_json(data, file_path, encoding='utf-8'):
    try:
        with open(file_path, 'w', encoding=encoding) as jsonfile:
            json.dump(data, jsonfile, ensure_ascii=False, indent=2)
    except Exception as e:
        raise ValueError(f"JSON conversion error: {e}")

def convert_to_xml(data, file_path, root_tag='root', record_tag='record', encoding='utf-8'):
    try:
        root = ET.Element(root_tag)
        for item in data:
            rec = ET.SubElement(root, record_tag)
            flat = flatten_dict(item)
            for k, v in flat.items():
                child = ET.SubElement(rec, k)
                child.text = str(v) if v is not None else ''
        tree = ET.ElementTree(root)
        tree.write(file_path, encoding=encoding, xml_declaration=True)
    except Exception as e:
        raise ValueError(f"XML conversion error: {e}")

def validate_data(data, schema):
    errors = []
    is_valid = True
    if not isinstance(data, list):
        data = [data]
    for idx, item in enumerate(data):
        if not isinstance(item, dict):
            errors.append(f"Item {idx} is not a dictionary")
            is_valid = False
            continue
        for key, expected_type in schema.items():
            if key not in item:
                errors.append(f"Item {idx} missing key '{key}'")
                is_valid = False
                continue
            value = item[key]
            if value is None:
                errors.append(f"Item {idx} key '{key}' is None")
                is_valid = False
            elif expected_type == "int":
                try:
                    int(value)
                except:
                    errors.append(f"Item {idx} key '{key}' should be int")
                    is_valid = False
            elif expected_type == "float":
                try:
                    float(value)
                except:
                    errors.append(f"Item {idx} key '{key}' should be float")
                    is_valid = False
            elif expected_type == "str":
                if not isinstance(value, str):
                    errors.append(f"Item {idx} key '{key}' should be str")
                    is_valid = False
    return is_valid, errors

def flatten_dict(d, parent_key='', sep='.'):
    items = {}
    for k, v in d.items():
        new_key = parent_key + sep + k if parent_key else k
        if isinstance(v, dict):
            items.update(flatten_dict(v, new_key, sep=sep))
        elif isinstance(v, list):
            # Convert list to string
            items[new_key] = json.dumps(v)
        else:
            items[new_key] = v
    return items

def orchestrate(file_path, schema, target_format=None, output_path=None, encoding='utf-8'):
    format_detected = detect_file_format(file_path)
    if format_detected == 'empty':
        raise ValueError("File is empty")
    if format_detected == 'unknown':
        raise ValueError("Could not detect file format")
    if format_detected == 'csv':
        data = parse_csv(file_path, encoding=encoding)
    elif format_detected == 'json':
        data = parse_json(file_path, encoding=encoding)
    elif format_detected == 'xml':
        data = parse_xml(file_path, encoding=encoding)
    else:
        raise ValueError("Unsupported file format")
    is_valid, errors = validate_data(data, schema)
    result = {
        'format': format_detected,
        'is_valid': is_valid,
        'errors': errors,
        'data': data
    }
    if target_format and output_path:
        if target_format == 'csv':
            convert_to_csv(data, output_path, encoding=encoding)
        elif target_format == 'json':
            convert_to_json(data, output_path, encoding=encoding)
        elif target_format == 'xml':
            convert_to_xml(data, output_path, encoding=encoding)
        else:
            raise ValueError("Unsupported target format")
        result['converted_to'] = target_format
        result['output_path'] = output_path
    return result

import threading
import pickle
import time
import re
from collections import OrderedDict
from functools import wraps

class CacheItem:
    __slots__ = ("value", "expire_at")

    def __init__(self, value, expire_at=None):
        self.value = value
        self.expire_at = expire_at

class LRUCache:
    def __init__(self, max_size=128, ttl=None, cleanup_interval=30):
        if not isinstance(max_size, int) or max_size <= 0:
            raise ValueError("max_size must be positive integer")
        if ttl is not None and (not isinstance(ttl, (int, float)) or ttl <= 0):
            raise ValueError("ttl must be positive number or None")
        self.max_size = max_size
        self.ttl = ttl
        self.cleanup_interval = cleanup_interval
        self._lock = threading.RLock()
        self._cache = OrderedDict()
        self._hits = 0
        self._misses = 0
        self._evictions = 0
        self._last_cleanup = time.monotonic()
        self._stop_cleaner = threading.Event()
        self._cleaner_thread = threading.Thread(target=self._active_cleanup, daemon=True)
        self._cleaner_thread.start()

    def _get_now(self):
        return time.monotonic()

    def _is_expired(self, item):
        return item.expire_at is not None and self._get_now() > item.expire_at

    def _purge_expired(self):
        now = self._get_now()
        keys_to_remove = []
        for key, item in list(self._cache.items()):
            if item.expire_at is not None and now > item.expire_at:
                keys_to_remove.append(key)
        for key in keys_to_remove:
            self._cache.pop(key, None)
            self._evictions += 1

    def _active_cleanup(self):
        while not self._stop_cleaner.is_set():
            with self._lock:
                self._purge_expired()
            self._stop_cleaner.wait(self.cleanup_interval)

    def set(self, key, value, ttl=None):
        if key is None:
            raise ValueError("key must not be None")
        with self._lock:
            expire_at = None
            ttl_used = ttl if ttl is not None else self.ttl
            if ttl_used is not None:
                expire_at = self._get_now() + ttl_used
            if key in self._cache:
                self._cache.pop(key)
            elif len(self._cache) >= self.max_size:
                _, evicted = self._cache.popitem(last=False)
                self._evictions += 1
            self._cache[key] = CacheItem(value, expire_at)

    def get(self, key, default=None):
        if key is None:
            raise ValueError("key must not be None")
        with self._lock:
            item = self._cache.get(key)
            if item is None:
                self._misses += 1
                return default
            if self._is_expired(item):
                self._cache.pop(key, None)
                self._evictions += 1
                self._misses += 1
                return default
            self._cache.move_to_end(key)
            self._hits += 1
            return item.value

    def __contains__(self, key):
        with self._lock:
            item = self._cache.get(key)
            if item is None:
                return False
            if self._is_expired(item):
                self._cache.pop(key, None)
                self._evictions += 1
                return False
            return True

    def delete(self, key):
        with self._lock:
            if key in self._cache:
                self._cache.pop(key)
                self._evictions += 1

    def clear(self):
        with self._lock:
            self._cache.clear()
            self._hits = 0
            self._misses = 0
            self._evictions = 0

    def invalidate(self, pattern):
        # Support both string regex and callable
        with self._lock:
            keys_to_remove = []
            if callable(pattern):
                for key in self._cache:
                    if pattern(key):
                        keys_to_remove.append(key)
            else:
                for key in self._cache:
                    try:
                        if re.match(pattern, str(key)):
                            keys_to_remove.append(key)
                    except Exception:
                        continue
            for key in keys_to_remove:
                self._cache.pop(key, None)
                self._evictions += 1

    def stats(self):
        with self._lock:
            total = self._hits + self._misses
            hit_rate = self._hits / total if total > 0 else 0.0
            return {
                "hits": self._hits,
                "misses": self._misses,
                "evictions": self._evictions,
                "hit_rate": hit_rate,
                "size": len(self._cache)
            }

    def save(self, filepath):
        with self._lock:
            with open(filepath, "wb") as f:
                # Only store non-expired items
                now = self._get_now()
                data = {
                    "max_size": self.max_size,
                    "ttl": self.ttl,
                    "cleanup_interval": self.cleanup_interval,
                    "cache": [
                        (key, item.value, item.expire_at - now if item.expire_at else None)
                        for key, item in self._cache.items()
                        if item.expire_at is None or now < item.expire_at
                    ],
                    "stats": (self._hits, self._misses, self._evictions)
                }
                pickle.dump(data, f)

    def load(self, filepath):
        with self._lock:
            with open(filepath, "rb") as f:
                data = pickle.load(f)
                self.max_size = data.get("max_size", self.max_size)
                self.ttl = data.get("ttl", self.ttl)
                self.cleanup_interval = data.get("cleanup_interval", self.cleanup_interval)
                self._cache.clear()
                now = self._get_now()
                for key, value, ttl_remain in data["cache"]:
                    expire_at = now + ttl_remain if ttl_remain is not None else None
                    self._cache[key] = CacheItem(value, expire_at)
                stats = data.get("stats", (0, 0, 0))
                self._hits, self._misses, self._evictions = stats
            # Restart cleaner if needed
            if not self._cleaner_thread.is_alive():
                self._stop_cleaner.clear()
                self._cleaner_thread = threading.Thread(target=self._active_cleanup, daemon=True)
                self._cleaner_thread.start()

    def stop(self):
        self._stop_cleaner.set()
        if self._cleaner_thread.is_alive():
            self._cleaner_thread.join(timeout=2)

    def keys(self):
        with self._lock:
            now = self._get_now()
            # Return only non-expired keys
            return [
                key for key, item in self._cache.items()
                if item.expire_at is None or now < item.expire_at
            ]

    def __del__(self):
        try:
            self.stop()
        except Exception:
            pass

def _make_cache_key(args, kwargs, typed=False):
    key = args
    if kwargs:
        for item in sorted(kwargs.items()):
            key += (item,)
    if typed:
        key += tuple(type(arg) for arg in args)
        if kwargs:
            key += tuple(type(v) for k, v in sorted(kwargs.items()))
    return key

def mcache(max_size=128, ttl=None, typed=False, cache_instance=None):
    def decorator(func):
        nonlocal cache_instance
        if cache_instance is None:
            cache_instance = LRUCache(max_size=max_size, ttl=ttl)

        @wraps(func)
        def wrapper(*args, **kwargs):
            key = _make_cache_key(args, kwargs, typed)
            try:
                result = cache_instance.get(key)
            except Exception:
                result = None
            if result is not None:
                return result
            # Miss
            val = func(*args, **kwargs)
            try:
                cache_instance.set(key, val)
            except Exception:
                pass
            return val

        wrapper.cache = cache_instance
        return wrapper
    return decorator

import argparse
import re
import json
import sys
import datetime
from collections import defaultdict, Counter, deque
from typing import Any, Dict, Generator, Iterable, List, Optional, Tuple, Union, Callable, Pattern

# ------------------------- Log Parsers ---------------------------

def parse_syslog_line(line: str) -> Optional[Dict[str, Any]]:
    syslog_re = re.compile(
        r'^(?P<date>\w{3} +\d{1,2} \d{2}:\d{2}:\d{2}) (?P<host>[\w\-.]+) (?P<proc>[\w\-\/]+)(?:\[(?P<pid>\d+)\])?: (?P<msg>.*)$'
    )
    mo = syslog_re.match(line)
    if not mo:
        return None
    now = datetime.datetime.now()
    try:
        # syslog omits year, infer current
        dt_str = f"{now.year} {mo.group('date')}"
        dt = datetime.datetime.strptime(dt_str, "%Y %b %d %H:%M:%S")
    except Exception:
        return None
    entry = {
        "datetime": dt,
        "host": mo.group('host'),
        "process": mo.group('proc'),
        "pid": int(mo.group('pid')) if mo.group('pid') else None,
        "message": mo.group('msg')
    }
    # Infer severity from message
    msg = mo.group('msg')
    sev = None
    sev_re = re.compile(r'\b(INFO|WARNING|ERROR|DEBUG|CRITICAL|NOTICE|WARN)\b', re.I)
    sev_mo = sev_re.search(msg)
    if sev_mo:
        sev = sev_mo.group(1).upper()
    entry['severity'] = sev
    entry['raw'] = line.rstrip('\n')
    return entry

def parse_apache_line(line: str) -> Optional[Dict[str, Any]]:
    # Common or combined log format
    log_pattern = re.compile(r'^(?P<ip>\S+) \S+ \S+ \[(?P<datetime>[^\]]+)\] "(?P<request>[^"]*)" (?P<status>\d{3}) (?P<size>\S+)(?: "(?P<referrer>[^"]*)" "(?P<useragent>[^"]*)")?$')
    mo = log_pattern.match(line)
    if not mo:
        return None
    try:
        dt = datetime.datetime.strptime(mo.group('datetime').split()[0], "%d/%b/%Y:%H:%M:%S")
    except Exception:
        return None
    entry = {
        "datetime": dt,
        "ip": mo.group('ip'),
        "request": mo.group('request'),
        "status": int(mo.group('status')),
        "size": int(mo.group('size')) if mo.group('size').isdigit() else None,
        "referrer": mo.group('referrer'),
        "useragent": mo.group('useragent'),
        "severity": infer_http_severity(mo.group('status')),
        "raw": line.rstrip('\n')
    }
    return entry

def parse_nginx_line(line: str) -> Optional[Dict[str, Any]]:
    # nginx default access log: '$remote_addr - $remote_user [$time_local] "$request" $status $body_bytes_sent "$http_referer" "$http_user_agent"'
    log_pattern = re.compile(r'^(?P<ip>\S+) \S+ \S+ \[(?P<datetime>[^]]+)\] "(?P<request>[^"]*)" (?P<status>\d{3}) (?P<size>\d+)(?: "(?P<referrer>[^"]*)" "(?P<useragent>[^"]*)")?$')
    mo = log_pattern.match(line)
    if not mo:
        return None
    try:
        dt = datetime.datetime.strptime(mo.group('datetime').split()[0], "%d/%b/%Y:%H:%M:%S")
    except Exception:
        return None
    entry = {
        "datetime": dt,
        "ip": mo.group('ip'),
        "request": mo.group('request'),
        "status": int(mo.group('status')),
        "size": int(mo.group('size')),
        "referrer": mo.group('referrer'),
        "useragent": mo.group('useragent'),
        "severity": infer_http_severity(mo.group('status')),
        "raw": line.rstrip('\n')
    }
    return entry

def parse_json_line(line: str) -> Optional[Dict[str, Any]]:
    try:
        log = json.loads(line)
    except Exception:
        return None
    # Expect fields: timestamp, severity, message, etc.
    dt = None
    for field in ('datetime', 'timestamp', 'time', 'date'):
        if field in log:
            try:
                dt = parse_date(log[field])
            except Exception:
                dt = None
            if dt:
                break
    log['datetime'] = dt
    log['severity'] = str(log.get('severity', '')).upper() if 'severity' in log else None
    log['raw'] = line.rstrip('\n')
    return log

def parse_date(val: str) -> Optional[datetime.datetime]:
    # Try multiple formats
    fmts = [
        "%Y-%m-%dT%H:%M:%S.%fZ",
        "%Y-%m-%dT%H:%M:%S.%f",
        "%Y-%m-%dT%H:%M:%S",
        "%Y-%m-%d %H:%M:%S",
        "%d/%b/%Y:%H:%M:%S",
        "%b %d %H:%M:%S"
    ]
    for fmt in fmts:
        try:
            return datetime.datetime.strptime(val, fmt)
        except Exception:
            continue
    # Try ISO
    try:
        return datetime.datetime.fromisoformat(val)
    except Exception:
        return None

def infer_http_severity(status: Union[str, int]) -> str:
    try:
        code = int(status)
    except Exception:
        return "INFO"
    if 500 <= code < 600:
        return "ERROR"
    elif 400 <= code < 500:
        return "WARNING"
    elif 100 <= code < 200 or 300 <= code < 400:
        return "INFO"
    elif 200 <= code < 300:
        return "INFO"
    else:
        return "INFO"

def guess_log_format(line: str) -> Optional[str]:
    if line.strip().startswith('{'):
        return 'json'
    if re.match(r'^\S+ - - \[', line):
        return 'apache'
    if re.match(r'^\S+ \S+ \S+ \[', line):
        return 'nginx'
    if re.match(r'^\w{3} +\d{1,2} \d\d:\d\d:\d\d ', line):
        return 'syslog'
    return None

PARSERS = {
    'apache': parse_apache_line,
    'nginx': parse_nginx_line,
    'syslog': parse_syslog_line,
    'json': parse_json_line
}

# ------------------------- Filtering ---------------------------

def filter_entries(
    entries: Iterable[Dict[str, Any]],
    severity: Optional[List[str]] = None,
    date_start: Optional[datetime.datetime] = None,
    date_end: Optional[datetime.datetime] = None,
    regex: Optional[Pattern] = None
) -> Generator[Dict[str, Any], None, None]:
    for entry in entries:
        if entry is None:
            continue
        # Severity
        if severity and entry.get('severity'):
            sev = entry['severity']
            if sev is not None and sev.upper() not in severity:
                continue
        # Date range
        dt = entry.get('datetime')
        if dt:
            if date_start and dt < date_start:
                continue
            if date_end and dt > date_end:
                continue
        # Regex pattern
        if regex:
            raw_line = entry.get('raw', '')
            if not regex.search(raw_line):
                continue
        yield entry

# ------------------------- Aggregation ---------------------------

def aggregate_stats(entries: Iterable[Dict[str, Any]]) -> Dict[str, Any]:
    error_counter = Counter()
    req_per_minute = defaultdict(int)
    top_ips = Counter()
    for entry in entries:
        # For re-use, we'll keep a copy in list. But caller should call this only on filtered generator.
        # Error counts
        sev = entry.get('severity', 'INFO')
        error_counter[sev] += 1
        # Requests per minute (if access log)
        dt = entry.get('datetime')
        if dt:
            minute = dt.replace(second=0, microsecond=0)
            req_per_minute[minute] += 1
        # Top IPs
        ip = entry.get('ip')
        if ip:
            top_ips[ip] += 1
    # Most common IPs (top 10)
    top_ips10 = top_ips.most_common(10)
    return {
        'error_counts': dict(error_counter),
        'requests_per_minute': {k.strftime('%Y-%m-%d %H:%M'): v for k, v in req_per_minute.items()},
        'top_ips': top_ips10
    }

# ---------------------- Anomaly Detection ------------------------

def detect_anomalies(
    entries: Iterable[Dict[str, Any]],
    window_size: int = 20,
    spike_factor: float = 3.0
) -> List[Dict[str, Any]]:
    """
    Detects sudden spikes in error counts using a rolling window.
    """
    anomalies = []
    # Rolling window for errors per minute
    err_counts = deque(maxlen=window_size)
    error_lines = []
    for entry in entries:
        dt = entry.get('datetime')
        sev = entry.get('severity', '')
        # Only look at ERROR/CRITICAL/5xx
        if sev in ('ERROR', 'CRITICAL'):
            minute = dt.replace(second=0, microsecond=0) if dt else None
            error_lines.append((minute, entry))
    # Group by minute
    errors_by_minute = defaultdict(list)
    for minute, entry in error_lines:
        if minute:
            errors_by_minute[minute].append(entry)
    sorted_minutes = sorted(errors_by_minute.keys())
    counts = [len(errors_by_minute[m]) for m in sorted_minutes]
    # Rolling window mean/std
    window = deque(maxlen=window_size)
    for i, minute in enumerate(sorted_minutes):
        count = len(errors_by_minute[minute])
        window.append(count)
        if i < window_size:
            continue
        mean = sum(list(window)[:-1]) / (window_size-1) if window_size > 1 else 0
        if mean == 0:
            continue
        if count > spike_factor * mean:
            anomalies.append({
                'minute': minute.strftime('%Y-%m-%d %H:%M'),
                'error_count': count,
                'avg_prev': mean,
                'factor': count / mean
            })
    return anomalies

# ------------------------- Reporting -----------------------------

def generate_text_report(stats: Dict[str, Any], anomalies: List[Dict[str, Any]]) -> str:
    lines = ["=== Log Summary Report ==="]
    lines.append("Severity counts:")
    for sev, cnt in stats.get('error_counts', {}).items():
        lines.append(f"  {sev}: {cnt}")
    lines.append("Requests per minute (top 10):")
    reqs = list(stats.get('requests_per_minute', {}).items())
    reqs.sort()
    for minute, count in reqs[-10:]:
        lines.append(f"  {minute}: {count}")
    lines.append("Top IP addresses:")
    for ip, count in stats.get('top_ips', []):
        lines.append(f"  {ip}: {count}")
    if anomalies:
        lines.append("\nDetected Anomalies (spikes in errors):")
        for anomaly in anomalies:
            lines.append(
                f"  {anomaly['minute']}: {anomaly['error_count']} errors (avg prev {anomaly['avg_prev']:.1f}, factor {anomaly['factor']:.2f})"
            )
    else:
        lines.append("\nNo significant error anomalies detected.")
    return '\n'.join(lines)

def generate_json_report(stats: Dict[str, Any], anomalies: List[Dict[str, Any]]) -> str:
    report = {
        "severity_counts": stats.get('error_counts', {}),
        "requests_per_minute": stats.get('requests_per_minute', {}),
        "top_ip_addresses": stats.get('top_ips', []),
        "anomalies": anomalies
    }
    return json.dumps(report, indent=2, default=str)

# ---------------------- File Streaming Logic ----------------------

def stream_log_entries(filename: str, log_format: Optional[str]=None) -> Generator[Dict[str, Any], None, None]:
    parser = None
    with open(filename, "r", encoding="utf-8", errors='replace') as f:
        # Guess format if not specified
        first_line = f.readline()
        if not log_format:
            detected = guess_log_format(first_line)
            if not detected:
                yield None
                return
            parser = PARSERS[detected]
        else:
            if log_format not in PARSERS:
                yield None
                return
            parser = PARSERS[log_format]
        # Parse first line
        entry = parser(first_line)
        if entry:
            yield entry
        # Continue rest
        for line in f:
            entry = parser(line)
            if entry:
                yield entry

# ------------------------- CLI Main -------------------------------

def parse_cli_args():
    parser = argparse.ArgumentParser(description="Log File Analyzer")
    parser.add_argument("logfile", help="Path to the log file")
    parser.add_argument("--format", choices=['syslog', 'apache', 'nginx', 'json'], help="Log format (autodetect by default)")
    parser.add_argument("--severity", nargs="+", help="Filter by severity (e.g. ERROR WARNING INFO)")
    parser.add_argument("--date-start", help="Filter entries after date (ISO 8601 or YYYY-MM-DD HH:MM:SS)")
    parser.add_argument("--date-end", help="Filter entries before date (ISO 8601 or YYYY-MM-DD HH:MM:SS)")
    parser.add_argument("--pattern", help="Regex pattern to match (in raw log lines)")
    parser.add_argument("--report", choices=["text", "json"], default="text", help="Report format")
    parser.add_argument("--anomaly-window", type=int, default=20, help="Anomaly detection window size (minutes)")
    parser.add_argument("--anomaly-factor", type=float, default=3.0, help="Spike factor for anomaly detection")
    return parser.parse_args()

def main():
    args = parse_cli_args()
    try:
        # Parse date filters
        dstart = parse_date(args.date_start) if args.date_start else None
        dend = parse_date(args.date_end) if args.date_end else None
        severity = [s.upper() for s in args.severity] if args.severity else None
        regex = re.compile(args.pattern) if args.pattern else None

        # Prepare streaming
        entries = list(stream_log_entries(args.logfile, args.format))
        entries_filtered = list(filter_entries(
            entries,
            severity=severity,
            date_start=dstart,
            date_end=dend,
            regex=regex
        ))

        stats = aggregate_stats(entries_filtered)
        anomalies = detect_anomalies(
            entries_filtered,
            window_size=args.anomaly_window,
            spike_factor=args.anomaly_factor
        )

        if args.report == "text":
            report = generate_text_report(stats, anomalies)
        else:
            report = generate_json_report(stats, anomalies)
        print(report)
    except KeyboardInterrupt:
        print("\nInterrupted.", file=sys.stderr)
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()

import logging
import itertools
from typing import Any, Callable, Iterable, List, Dict, Optional, Tuple, Union
from collections import defaultdict, abc
from copy import deepcopy

# Error recovery strategies
SKIP = "skip"
RETRY = "retry"
ABORT = "abort"
DEFAULT = "default"

# Configure logging
logger = logging.getLogger("Pipeline")
logger.setLevel(logging.INFO)
handler = logging.StreamHandler()
formatter = logging.Formatter('%(levelname)s | %(asctime)s | %(message)s')
handler.setFormatter(formatter)
if not logger.hasHandlers():
    logger.addHandler(handler)

class TransformError(Exception):
    pass

class ValidationError(Exception):
    pass

class BaseTransform:
    def __init__(self, 
                 validator: Optional[Callable[[Any], bool]] = None, 
                 error_strategy: str = SKIP,
                 on_error_default: Any = None,
                 max_retries: int = 1,
                 name: str = ""
                 ):
        self.validator = validator
        self.error_strategy = error_strategy
        self.on_error_default = on_error_default
        self.max_retries = max_retries
        self.name = name or self.__class__.__name__

    def _validate(self, item):
        if self.validator:
            try:
                if not self.validator(item):
                    logger.warning(f"Validation failed in {self.name}: {item}")
                    raise ValidationError(f"Validation failed for item: {item}")
                return True
            except Exception as e:
                logger.error(f"Error during validation in {self.name}: {str(e)}")
                raise ValidationError(e)
        return True

    def handle_error(self, exc, item, func, retry_count):
        logger.error(f"Error in {self.name}: {exc}. Error strategy: {self.error_strategy}. Item: {item}")
        if self.error_strategy == SKIP:
            return (True, None)
        elif self.error_strategy == RETRY:
            if retry_count < self.max_retries:
                logger.info(f"Retrying {self.name} for item (attempt {retry_count+1}/{self.max_retries})...")
                return (False, None)
            else:
                logger.warning(f"Max retries reached in {self.name} for item: {item}. Skipping.")
                return (True, None)
        elif self.error_strategy == ABORT:
            logger.critical(f"Aborting pipeline in {self.name} due to error.")
            raise exc
        elif self.error_strategy == DEFAULT:
            logger.info(f"Supplying default value in {self.name} for item: {item}.")
            return (True, deepcopy(self.on_error_default))
        else:
            logger.warning(f"Unknown error strategy '{self.error_strategy}' in {self.name}. Skipping.")
            return (True, None)

    def __call__(self, data: Iterable) -> Iterable:
        raise NotImplementedError

class FilterTransform(BaseTransform):
    def __init__(self, predicate: Callable[[Any], bool], **kwargs):
        super().__init__(**kwargs)
        self.predicate = predicate

    def __call__(self, data: Iterable) -> Iterable:
        for idx, item in enumerate(data):
            try:
                self._validate(item)
                if self.predicate(item):
                    yield item
                else:
                    logger.debug(f"Filtered out item in {self.name}: {item}")
            except Exception as exc:
                finished, result = self.handle_error(exc, item, self.predicate, 0)
                if not finished:
                    continue
                # skip or default applies (do not yield anything for filtered out)

class MapTransform(BaseTransform):
    def __init__(self, func: Callable[[Any], Any], **kwargs):
        super().__init__(**kwargs)
        self.func = func

    def __call__(self, data: Iterable) -> Iterable:
        for idx, item in enumerate(data):
            retry_count = 0
            while True:
                try:
                    self._validate(item)
                    result = self.func(item)
                    self._validate(result)
                    yield result
                    break
                except Exception as exc:
                    finished, result_val = self.handle_error(exc, item, self.func, retry_count)
                    retry_count += 1
                    if finished:
                        if self.error_strategy == DEFAULT:
                            self._validate(result_val)
                            yield result_val
                        break

class GroupByTransform(BaseTransform):
    def __init__(self, key_func: Callable[[Any], Any], **kwargs):
        super().__init__(**kwargs)
        self.key_func = key_func

    def __call__(self, data: Iterable) -> Iterable:
        groups = defaultdict(list)
        for idx, item in enumerate(data):
            retry_count = 0
            while True:
                try:
                    self._validate(item)
                    key = self.key_func(item)
                    groups[key].append(item)
                    break
                except Exception as exc:
                    finished, result_val = self.handle_error(exc, item, self.key_func, retry_count)
                    retry_count += 1
                    if finished:
                        break
        for k, v in groups.items():
            yield (k, v)

class AggregateTransform(BaseTransform):
    def __init__(self, agg_func: Callable[[Any, Iterable], Any], **kwargs):
        super().__init__(**kwargs)
        self.agg_func = agg_func

    def __call__(self, data: Iterable) -> Iterable:
        for idx, (key, group) in enumerate(data):
            retry_count = 0
            while True:
                try:
                    result = self.agg_func(key, group)
                    self._validate(result)
                    yield result
                    break
                except Exception as exc:
                    finished, result_val = self.handle_error(exc, (key, group), self.agg_func, retry_count)
                    retry_count += 1
                    if finished:
                        if self.error_strategy == DEFAULT:
                            self._validate(result_val)
                            yield result_val
                        break

class BranchingTransform(BaseTransform):
    def __init__(self, pipelines: List["Pipeline"], split_func: Optional[Callable[[Any], List[int]]]=None, **kwargs):
        super().__init__(**kwargs)
        self.pipelines = pipelines
        self.split_func = split_func or (lambda item: list(range(len(self.pipelines))))

    def __call__(self, data: Iterable) -> List[List[Any]]:
        outputs = [[] for _ in self.pipelines]
        for item in data:
            try:
                self._validate(item)
                pipe_idxs = self.split_func(item)
                for idx in pipe_idxs:
                    outputs[idx].append(item)
            except Exception as exc:
                finished, _ = self.handle_error(exc, item, self.split_func, 0)
                if not finished:
                    continue
        results = []
        for i, pipe in enumerate(self.pipelines):
            out = list(pipe(outputs[i]))
            results.append(out)
        return results

class ValidatorTransform(BaseTransform):
    def __init__(self, validator: Callable[[Any], bool], **kwargs):
        super().__init__(validator=validator, **kwargs)

    def __call__(self, data: Iterable) -> Iterable:
        for item in data:
            try:
                self._validate(item)
                yield item
            except Exception as exc:
                finished, _ = self.handle_error(exc, item, self.validator, 0)
                if not finished:
                    continue

class ResultsCollector:
    def __init__(self, merge_func: Optional[Callable[[List[List[Any]]], List[Any]]] = None):
        self.merge_func = merge_func or self.default_merge

    @staticmethod
    def default_merge(outputs: List[List[Any]]) -> List[Any]:
        # merge keeping order; flatten
        return list(itertools.chain.from_iterable(outputs))

    def __call__(self, outputs: List[List[Any]]) -> List[Any]:
        return self.merge_func(outputs)

class Pipeline:
    def __init__(self, transforms: Optional[List[BaseTransform]] = None, name: str = None):
        self.transforms = transforms or []
        self.name = name or "Pipeline"
        self.collector = None

    def add_transform(self, transform: BaseTransform) -> "Pipeline":
        self.transforms.append(transform)
        return self

    def set_collector(self, collector: ResultsCollector):
        self.collector = collector
        return self

    def _process_with_progress(self, data: Iterable) -> Iterable:
        count = 0
        for item in data:
            count += 1
            yield item
        logger.info(f"{self.name} processed {count} items.")

    def __call__(self, data: Iterable) -> Any:
        logger.info(f"Starting pipeline: {self.name}")
        data = iter(data)
        if isinstance(data, abc.Sized):
            nitems = len(data)
        else:
            nitems = "unknown"
        stage = 0
        try:
            for idx, transform in enumerate(self.transforms):
                logger.info(f"Stage {stage}: {transform.name}")
                if isinstance(transform, BranchingTransform):
                    branch_outputs = transform(data)
                    if self.collector:
                        output = self.collector(branch_outputs)
                    else:
                        output = list(itertools.chain.from_iterable(branch_outputs))
                    logger.info(f"Collected {len(output)} items from branches.")
                    return output
                else:
                    data = transform(data)
                stage += 1
            # progress tracking for last stage
            data = self._process_with_progress(data)
            output = list(data)
            logger.info(f"Pipeline '{self.name}' complete. Output size: {len(output)}")
            return output
        except Exception as e:
            logger.critical(f"Uncaught pipeline error in '{self.name}': {str(e)}", exc_info=True)
            raise

# Example built-in validators (for external use)
def type_validator(expected_type: Union[type, Tuple[type, ...]]) -> Callable[[Any], bool]:
    def _validator(item):
        return isinstance(item, expected_type)
    return _validator

def not_empty_validator(item):
    if hasattr(item, "__len__"):
        return len(item) > 0
    return bool(item)

import threading
import queue
import json
import copy
from typing import Any, Callable, Dict, Optional, List, Set, Tuple, Union


class StateMachineError(Exception):
    pass


class InvalidTransitionError(StateMachineError):
    pass


class MissingStateError(StateMachineError):
    pass


class CircularDependencyError(StateMachineError):
    pass


class NonDeterministicError(StateMachineError):
    pass


class IncompleteDefinitionError(StateMachineError):
    pass


class State:
    def __init__(
        self,
        name: str,
        entry_action: Optional[Callable[['StateMachine', Any], None]] = None,
        exit_action: Optional[Callable[['StateMachine', Any], None]] = None,
    ):
        self.name = name
        self.entry_action = entry_action
        self.exit_action = exit_action

    def on_entry(self, machine, event):
        if self.entry_action:
            self.entry_action(machine, event)

    def on_exit(self, machine, event):
        if self.exit_action:
            self.exit_action(machine, event)


class Transition:
    def __init__(
        self,
        source: str,
        dest: str,
        event: str,
        guard: Optional[Callable[['StateMachine', Any], bool]] = None,
        action: Optional[Callable[['StateMachine', Any], None]] = None,
        priority: int = 100,
    ):
        self.source = source
        self.dest = dest
        self.event = event
        self.guard = guard
        self.action = action
        self.priority = priority

    def is_triggered(self, machine, event_payload):
        if self.guard:
            try:
                return self.guard(machine, event_payload)
            except Exception as e:
                raise StateMachineError(f"Error in guard for transition {self.source} --({self.event})-> {self.dest}: {e}")
        return True


class Event:
    def __init__(self, name: str, payload: Any = None, priority: int = 100):
        self.name = name
        self.payload = payload
        self.priority = priority

    def __lt__(self, other):
        return self.priority < other.priority


class StateMachine:
    def __init__(self, initial_state: str):
        self._states: Dict[str, State] = {}
        self._transitions: List[Transition] = []
        self._current_state: Optional[str] = None
        self._history: List[Dict] = []
        self._event_queue = queue.PriorityQueue()
        self._lock = threading.RLock()
        self._initial_state = initial_state
        self._state_graph_cached: Optional[Dict[str, List[Transition]]] = None

    def add_state(self, name: str, entry_action: Optional[Callable[['StateMachine', Any], None]] = None,
                  exit_action: Optional[Callable[['StateMachine', Any], None]] = None):
        with self._lock:
            if name in self._states:
                raise StateMachineError(f"State '{name}' already exists")
            self._states[name] = State(name, entry_action, exit_action)

    def add_transition(self, source: str, dest: str, event: str,
                      guard: Optional[Callable[['StateMachine', Any], bool]] = None,
                      action: Optional[Callable[['StateMachine', Any], None]] = None,
                      priority: int = 100):
        with self._lock:
            if source not in self._states or dest not in self._states:
                raise MissingStateError(f"Missing source or dest state: {source}, {dest}")
            transition = Transition(source, dest, event, guard, action, priority)
            self._transitions.append(transition)
            self._state_graph_cached = None

    def set_initial_state(self, state: str):
        with self._lock:
            if state not in self._states:
                raise MissingStateError(f"Initial state '{state}' is not defined.")
            self._initial_state = state

    def start(self):
        with self._lock:
            if self._initial_state not in self._states:
                raise MissingStateError(f"Initial state '{self._initial_state}' is not defined.")
            self._current_state = self._initial_state
            self._history.clear()
            self._call_entry(self._current_state, None)

    def _call_entry(self, state_name: str, event_payload: Any):
        state = self._states[state_name]
        try:
            state.on_entry(self, event_payload)
        except Exception as e:
            raise StateMachineError(f"Error in entry action of state '{state_name}': {e}")

    def _call_exit(self, state_name: str, event_payload: Any):
        state = self._states[state_name]
        try:
            state.on_exit(self, event_payload)
        except Exception as e:
            raise StateMachineError(f"Error in exit action of state '{state_name}': {e}")

    def _record_history(self):
        hist = dict(current_state=self._current_state,
                    states=copy.deepcopy(self._states),
                    transitions=copy.deepcopy(self._transitions))
        self._history.append(hist)

    def undo(self):
        with self._lock:
            if not self._history:
                raise StateMachineError("No history to undo")
            prev = self._history.pop()
            self._current_state = prev['current_state']
            self._states = prev['states']
            self._transitions = prev['transitions']

    def process_event(self, event_name: str, payload: Any = None, priority: int = 100):
        self._event_queue.put(Event(event_name, payload, priority))
        self._process_events()

    def _find_eligible_transitions(self, state_name: str, event_name: str, event_payload: Any) -> List[Transition]:
        transitions = [
            t for t in self._transitions
            if t.source == state_name and t.event == event_name and t.is_triggered(self, event_payload)
        ]
        return sorted(transitions, key=lambda t: t.priority)

    def _process_transition(self, transition: Transition, event_payload: Any):
        self._record_history()
        self._call_exit(self._current_state, event_payload)
        if transition.action:
            try:
                transition.action(self, event_payload)
            except Exception as e:
                raise StateMachineError(f"Error in transition action from {transition.source} to {transition.dest}: {e}")
        self._current_state = transition.dest
        self._call_entry(self._current_state, event_payload)

    def _process_events(self):
        with self._lock:
            while not self._event_queue.empty():
                event: Event = self._event_queue.get(False)
                state_name = self._current_state
                if state_name is None:
                    raise StateMachineError("State machine not started.")
                transitions = self._find_eligible_transitions(state_name, event.name, event.payload)
                if not transitions:
                    raise InvalidTransitionError(f"No valid transition for event '{event.name}' in state '{state_name}'.")
                if len(transitions) > 1:
                    raise NonDeterministicError(
                        f"Non-determinism detected: multiple transitions ({len(transitions)}) from state '{state_name}' on event '{event.name}'."
                    )
                transition = transitions[0]
                self._process_transition(transition, event.payload)

    def get_current_state(self) -> str:
        return self._current_state

    def get_possible_events(self) -> Set[str]:
        state = self._current_state
        if state is None:
            return set()
        return {t.event for t in self._transitions if t.source == state}

    def serialize(self) -> str:
        with self._lock:
            data = {
                'current_state': self._current_state,
                'history': [
                    {
                        'current_state': h['current_state'],
                        # State and Transition objects are not serializable,
                        # so we only store names/essentials for history.
                        'states': list(h['states'].keys()),
                        'transitions': [
                            {
                                'source': tr.source,
                                'dest': tr.dest,
                                'event': tr.event,
                                'priority': tr.priority
                            } for tr in h['transitions']
                        ]
                    } for h in self._history
                ]
            }
            return json.dumps(data)

    def deserialize(self, data: str):
        with self._lock:
            obj = json.loads(data)
            self._current_state = obj['current_state']
            # Cannot restore custom actions/guards from JSON,
            # so history is present but not complete on restore.
            self._history.clear()
            for h in obj['history']:
                self._history.append({
                    'current_state': h['current_state'],
                    'states': {name: self._states[name] for name in h['states']},
                    'transitions': [
                        t for t in self._transitions
                        if (t.source, t.dest, t.event, t.priority) in
                        {(tr['source'], tr['dest'], tr['event'], tr['priority']) for tr in h['transitions']}
                    ]
                })

    def _build_state_graph(self) -> Dict[str, List[Transition]]:
        if self._state_graph_cached is not None:
            return self._state_graph_cached
        graph: Dict[str, List[Transition]] = {}
        for t in self._transitions:
            if t.source not in graph:
                graph[t.source] = []
            graph[t.source].append(t)
        self._state_graph_cached = graph
        return graph

    def _detect_cycles(self):
        graph = self._build_state_graph()
        visited = set()
        stack = set()

        def visit(node):
            if node in stack:
                raise CircularDependencyError(f"Circular dependency detected at state '{node}'.")
            if node in visited:
                return
            stack.add(node)
            for t in graph.get(node, []):
                visit(t.dest)
            stack.remove(node)
            visited.add(node)

        for state in self._states:
            visit(state)

    def _validate_states(self):
        # All state names used in transitions are present.
        for t in self._transitions:
            if t.source not in self._states or t.dest not in self._states:
                raise IncompleteDefinitionError(f"Transition from '{t.source}' to '{t.dest}' references missing state.")

    def _validate_determinism(self):
        # For each (state, event), at most one enabled transition (disregarding guard for strict determinism)
        seen: Dict[Tuple[str, str], int] = {}
        for t in self._transitions:
            key = (t.source, t.event)
            if key in seen:
                raise NonDeterministicError(f"Multiple transitions from '{t.source}' on event '{t.event}'.")
            seen[key] = 1

    def validate(self):
        with self._lock:
            self._validate_states()
            self._validate_determinism()
            self._detect_cycles()
            if not self._states:
                raise IncompleteDefinitionError("No states are defined.")
            if not self._transitions:
                raise IncompleteDefinitionError("No transitions are defined.")
            if self._initial_state not in self._states:
                raise IncompleteDefinitionError("Initial state is not among defined states.")

    def visualize(self) -> str:
        with self._lock:
            lines = ["digraph FSM {", "    rankdir=LR;"]
            # States.
            for state in self._states:
                if state == self._initial_state:
                    lines.append(f'    "{state}" [shape=doublecircle];')
                else:
                    lines.append(f'    "{state}" [shape=circle];')
            # Transitions.
            for t in self._transitions:
                label = t.event
                if t.guard:
                    label += " [guard]"
                if t.action:
                    label += " / [action]"
                lines.append(f'    "{t.source}" -> "{t.dest}" [label="{label}"];')
            lines.append("}")
            return "\n".join(lines)

