class TokenBucket:
    def __init__(self, rate, capacity):
        self.capacity = float(capacity)
        self.tokens = float(capacity)
        self.rate = float(rate)
        self.lock = threading.Lock()
        self.timestamp = time.monotonic()

    def consume(self, tokens=1):
        with self.lock:
            now = time.monotonic()
            elapsed = now - self.timestamp
            self.tokens = min(self.capacity, self.tokens + elapsed * self.rate)
            self.timestamp = now
            if self.tokens >= tokens:
                self.tokens -= tokens
                return True
            return False

class HTTPResponseCacheEntry:
    def __init__(self, url, response, headers):
        self.url = url
        self.response = response
        self.headers = headers
        self.etag = headers.get('ETag')
        self.last_modified = headers.get('Last-Modified')
        self.timestamp = time.time()

class HTTPResponseCache:
    def __init__(self, max_size=CACHE_MAX_SIZE):
        self.lock = threading.Lock()
        self.max_size = max_size
        self.cache = {}
        self.lru = deque()

    def get(self, url):
        with self.lock:
            entry = self.cache.get(url)
            if entry:
                self.lru.remove(url)
                self.lru.append(url)
                return entry
            return None

    def set(self, url, response, headers):
        with self.lock:
            if url in self.cache:
                self.lru.remove(url)
            elif len(self.cache) >= self.max_size:
                evict = self.lru.popleft()
                self.cache.pop(evict, None)
            entry = HTTPResponseCacheEntry(url, response, headers)
            self.cache[url] = entry
            self.lru.append(url)

    def clear(self):
        with self.lock:
            self.cache.clear()
            self.lru.clear()

class HTTPConnectionPool:
    def __init__(self, max_size=MAX_POOL_SIZE):
        self.lock = threading.Lock()
        self.max_size = max_size
        self._handlers = []

    def get_opener(self, cookie_jar):
        with self.lock:
            for opener, inuse in self._handlers:
                if not inuse:
                    self._handlers.remove((opener, inuse))
                    self._handlers.append((opener, True))
                    return opener
            if len(self._handlers) < self.max_size:
                cookie_processor = urllib.request.HTTPCookieProcessor(cookie_jar)
                opener = urllib.request.build_opener(cookie_processor)
                self._handlers.append((opener, True))
                return opener
            # Pool exhausted, pick LRU in-use opener
            opener, _ = self._handlers.pop(0)
            self._handlers.append((opener, True))
            return opener

    def release_opener(self, opener):
        with self.lock:
            for i, (op, inuse) in enumerate(self._handlers):
                if op is opener:
                    self._handlers[i] = (op, False)
                    break

class Metrics:
    def __init__(self):
        self.lock = threading.Lock()
        self.metrics = defaultdict(lambda: defaultdict(int))

    def log(self, method, status_code, elapsed):
        with self.lock:
            self.metrics[method]['count'] += 1
            self.metrics[method]['status_%d' % status_code] += 1
            self.metrics[method]['time_total'] += elapsed

    def get_stats(self):
        with self.lock:
            return dict(self.metrics)

class HTTPClient:
    def __init__(self, rate=5, capacity=10, pool_size=MAX_POOL_SIZE, cache_size=CACHE_MAX_SIZE,
                 connect_timeout=DEFAULT_CONNECT_TIMEOUT, read_timeout=DEFAULT_READ_TIMEOUT):
        self.cookie_jar = http.cookiejar.CookieJar()
        self.pool = HTTPConnectionPool(max_size=pool_size)
        self.cache = HTTPResponseCache(max_size=cache_size)
        self.rate_limiter = TokenBucket(rate, capacity)
        self.metrics = Metrics()
        self.connect_timeout = connect_timeout
        self.read_timeout = read_timeout

    def request(self, method, url, headers=None, data=None, params=None, retries=MAX_RETRIES, allow_redirects=True, timeout=None):
        method = method.upper()
        headers = dict(headers) if headers else {}
        if params and method in ("GET", "DELETE"):
            url = self._encode_url_params(url, params)
        elif params and method in ("POST", "PUT"):
            data = urllib.parse.urlencode(params).encode()

        # Handle Caching
        cache_entry = None
        if method == "GET":
            cache_entry = self.cache.get(url)
            if cache_entry:
                self._add_cache_conditional_headers(headers, cache_entry)

        # Respect rate limit
        while not self.rate_limiter.consume():
            logger.info("Rate limited. Sleeping...")
            time.sleep(0.1)

        attempt = 0
        total_elapsed = 0.0
        response_data = None
        status_code = None

        while attempt <= retries:
            opener = self.pool.get_opener(self.cookie_jar)
            try:
                request_obj = urllib.request.Request(url, data=data, headers=headers, method=method)
                t_start = time.monotonic()
                try:
                    response = opener.open(
                        request_obj,
                        timeout=timeout or self.connect_timeout
                    )
                except urllib.error.HTTPError as e:
                    response = e
                t_end = time.monotonic()
                elapsed = t_end - t_start
                total_elapsed += elapsed
                status_code = getattr(response, 'code', None) or getattr(response, 'status', None)
                resp_headers = dict(response.headers)
                content = None
                if status_code == 304 and cache_entry:
                    logger.info("Cache HIT for %s", url)
                    content = cache_entry.response
                else:
                    content = response.read()
                    if method == "GET" and status_code == 200:
                        self.cache.set(url, content, resp_headers)
                self.metrics.log(method, status_code, elapsed)
                self._log_request_response(method, url, headers, data, status_code, resp_headers, content, elapsed)
                if 200 <= status_code < 400:
                    self.pool.release_opener(opener)
                    return {
                        'status': status_code,
                        'headers': resp_headers,
                        'content': content,
                        'url': response.geturl() if hasattr(response, 'geturl') else url
                    }
                elif 400 <= status_code < 500:
                    logger.warning("Client Error: %d %s", status_code, url)
                    # For 4xx errors, do not retry (worst-case for 429, wait briefly)
                    if status_code == 429:
                        retry_after = resp_headers.get("Retry-After")
                        if retry_after:
                            try:
                                delay = int(retry_after)
                            except ValueError:
                                delay = 5
                            time.sleep(delay)
                    self.pool.release_opener(opener)
                    raise urllib.error.HTTPError(url, status_code, "Client Error", resp_headers, None)
                elif 500 <= status_code < 600:
                    logger.warning("Server Error: %d %s. Retrying...", status_code, url)
                    # For 5xx errors, apply exponential backoff
                    self.pool.release_opener(opener)
                    if attempt == retries:
                        raise urllib.error.HTTPError(url, status_code, "Server Error", resp_headers, None)
                    else:
                        self._wait_exponential_backoff(attempt)
                response.close()
            except (urllib.error.URLError, TimeoutError) as exc:
                logger.error("Request failed: %s", exc)
                if attempt == retries:
                    self.pool.release_opener(opener)
                    raise
                else:
                    self._wait_exponential_backoff(attempt)
            except Exception as exc:
                logger.error("Exception during request: %s", exc)
                self.pool.release_opener(opener)
                raise
            attempt += 1
            self.pool.release_opener(opener)
        raise urllib.error.URLError("Failed to complete request after retries")

    def get(self, url, headers=None, params=None, **kwargs):
        return self.request("GET", url, headers=headers, params=params, **kwargs)

    def post(self, url, headers=None, data=None, params=None, **kwargs):
        return self.request("POST", url, headers=headers, data=data, params=params, **kwargs)

    def put(self, url, headers=None, data=None, params=None, **kwargs):
        return self.request("PUT", url, headers=headers, data=data, params=params, **kwargs)

    def delete(self, url, headers=None, params=None, **kwargs):
        return self.request("DELETE", url, headers=headers, params=params, **kwargs)

    def _encode_url_params(self, url, params):
        scheme, netloc, path, query, frag = urllib.parse.urlsplit(url)
        new_query = urllib.parse.urlencode(params)
        if query:
            query = "%s&%s" % (query, new_query)
        else:
            query = new_query
        return urllib.parse.urlunsplit((scheme, netloc, path, query, frag))

    def _add_cache_conditional_headers(self, headers, cache_entry):
        if cache_entry.etag:
            headers['If-None-Match'] = cache_entry.etag
        if cache_entry.last_modified:
            headers['If-Modified-Since'] = cache_entry.last_modified

    def _wait_exponential_backoff(self, attempt):
        backoff = BASE_BACKOFF * (2 ** attempt)
        jitter = random.uniform(0, 0.2)
        delay = backoff + jitter
        logger.info("Backoff sleeping for %.2fs", delay)
        time.sleep(delay)

    def _log_request_response(self, method, url, headers, data, status, resp_headers, content, elapsed):
        logger.info(
            "%s %s [%d] %.2fms\nRequest headers: %s\nResponse headers: %s",
            method, url, status, elapsed*1000, headers, resp_headers
        )

    def clear_cache(self):
        self.cache.clear()

    def get_metrics(self):
        return self.metrics.get_stats()

    def get_cookies(self, url=None):
        if url:
            req = urllib.request.Request(url)
            self.cookie_jar.add_cookie_header(req)
            return req.headers.get("Cookie")
        return [cookie for cookie in self.cookie_jar]

    def set_cookie(self, name, value, domain):
        cookie = http.cookiejar.Cookie(
            version=0, name=name, value=value,
            port=None, port_specified=False,
            domain=domain, domain_specified=True, domain_initial_dot=domain.startswith('.'),
            path='/', path_specified=True,
            secure=False, expires=None, discard=True,
            comment=None, comment_url=None, rest={}
        )
        self.cookie_jar.set_cookie(cookie)

import threading
import time
import heapq
import uuid
import pickle
import os
from collections import defaultdict, deque
from concurrent.futures import ThreadPoolExecutor, as_completed
from typing import List, Dict, Callable, Any, Optional, Set, Tuple, Union
from enum import Enum
import signal

class TaskStatus(Enum):
    PENDING = "PENDING"
    RUNNING = "RUNNING"
    SUCCESS = "SUCCESS"
    FAILED = "FAILED"
    DEAD = "DEAD"
    SKIPPED = "SKIPPED"

class Task:
    def __init__(
        self,
        func: Callable[[], Any],
        dependencies: Optional[List[str]] = None,
        priority: int = 0,
        timeout: int = 30,
        name: Optional[str] = None,
        max_retries: int = 3,
        backoff: float = 1.0,
        est_runtime: float = 1.0,
    ):
        self.id = name or str(uuid.uuid4())
        self.dependencies = set(dependencies) if dependencies else set()
        self.priority = priority
        self.timeout = timeout
        self.func = func
        self.status = TaskStatus.PENDING
        self.result = None
        self.exception = None
        self.max_retries = max_retries
        self.backoff = backoff
        self.attempts = 0
        self.est_runtime = est_runtime
        self.start_time = None
        self.end_time = None

    def run(self):
        self.status = TaskStatus.RUNNING
        self.start_time = time.time()
        try:
            res = self.func()
            self.result = res
            self.status = TaskStatus.SUCCESS
            self.end_time = time.time()
            return res
        except Exception as e:
            self.exception = e
            self.status = TaskStatus.FAILED
            self.end_time = time.time()
            raise

    def is_alive(self):
        if self.status not in [TaskStatus.RUNNING, TaskStatus.PENDING]:
            return False
        if self.start_time is None:
            return True
        return (time.time() - self.start_time) <= self.timeout

    def to_dict(self):
        return {
            "id": self.id,
            "dependencies": list(self.dependencies),
            "priority": self.priority,
            "timeout": self.timeout,
            "status": self.status.value,
            "result": self.result,
            "exception": str(self.exception) if self.exception else None,
            "attempts": self.attempts,
            "max_retries": self.max_retries,
            "backoff": self.backoff,
            "est_runtime": self.est_runtime,
            "start_time": self.start_time,
            "end_time": self.end_time,
        }

class ScheduleStrategy(Enum):
    FIFO = "FIFO"
    PRIORITY = "PRIORITY"
    SHORTEST_JOB_FIRST = "SJF"

class Scheduler:
    def __init__(
        self,
        max_workers: int = 4,
        dead_task_timeout: float = 60,
        strategy: ScheduleStrategy = ScheduleStrategy.FIFO,
        state_path: str = "scheduler_state.pkl",
    ):
        self.tasks: Dict[str, Task] = {}
        self.lock = threading.Lock()
        self.max_workers = max_workers
        self.dead_task_timeout = dead_task_timeout
        self.strategy = strategy
        self.task_graph = defaultdict(set)
        self.reverse_graph = defaultdict(set)
        self.ready_queue = []
        self.running_tasks: Set[str] = set()
        self.finished_tasks: Set[str] = set()
        self.executor = ThreadPoolExecutor(max_workers=self.max_workers)
        self.state_path = state_path
        self.shutdown_flag = threading.Event()
        self.eta_lock = threading.Lock()
        self._load_state()
        signal.signal(signal.SIGINT, self._signal_handler)
        signal.signal(signal.SIGTERM, self._signal_handler)

    def add_task(self, task: Task):
        with self.lock:
            if task.id in self.tasks:
                raise ValueError(f"Task {task.id} already exists.")
            self.tasks[task.id] = task
            for dep in task.dependencies:
                self.task_graph[dep].add(task.id)
                self.reverse_graph[task.id].add(dep)
            if not task.dependencies:
                self._enqueue_ready_task(task)

    def _enqueue_ready_task(self, task: Task):
        entry = self._task_queue_entry(task)
        heapq.heappush(self.ready_queue, entry)

    def _task_queue_entry(self, task: Task):
        if self.strategy == ScheduleStrategy.FIFO:
            # Use insertion order -- can use timestamp or counter; here, use start_time or 0
            return (task.start_time or 0, task.id)
        elif self.strategy == ScheduleStrategy.PRIORITY:
            # Lower value = higher priority
            return (task.priority, task.id)
        elif self.strategy == ScheduleStrategy.SHORTEST_JOB_FIRST:
            return (task.est_runtime, task.id)
        else:
            return (0, task.id)

    def _resolve_dependencies(self):
        # Find update for missing dependencies or cycles
        all_task_ids = set(self.tasks.keys())
        for tid, task in self.tasks.items():
            for dep in task.dependencies:
                if dep not in self.tasks:
                    raise ValueError(f"Task {tid} depends on missing task {dep}")
        # Detect cycle
        visited = set()
        temp = set()
        def visit(nid):
            if nid in temp:
                raise ValueError("Circular dependency detected.")
            if nid not in visited:
                temp.add(nid)
                for dep in self.reverse_graph[nid]:
                    visit(dep)
                temp.remove(nid)
                visited.add(nid)
        for tid in self.tasks:
            visit(tid)

    def _topological_order(self) -> List[str]:
        indegree = {tid: len(task.dependencies) for tid, task in self.tasks.items()}
        queue = deque([tid for tid, task in self.tasks.items() if not task.dependencies])
        order = []
        while queue:
            tid = queue.popleft()
            order.append(tid)
            for dependent in self.task_graph[tid]:
                indegree[dependent] -= 1
                if indegree[dependent] == 0:
                    queue.append(dependent)
        if len(order) != len(self.tasks):
            raise ValueError("Circular dependency detected in task graph.")
        return order

    def _get_ready_tasks(self) -> List[Task]:
        ready = []
        with self.lock:
            for tid, task in self.tasks.items():
                if task.status == TaskStatus.PENDING and all(
                    self.tasks[dep].status == TaskStatus.SUCCESS for dep in task.dependencies
                ):
                    ready.append(task)
        return ready

    def _detect_dead_tasks(self):
        now = time.time()
        to_dead = []
        with self.lock:
            for tid in self.running_tasks:
                task = self.tasks[tid]
                if task.status == TaskStatus.RUNNING and task.start_time is not None:
                    if now - task.start_time > max(task.timeout, self.dead_task_timeout):
                        to_dead.append(tid)
            for tid in to_dead:
                task = self.tasks[tid]
                task.status = TaskStatus.DEAD
                self.running_tasks.discard(tid)
        return to_dead

    def _retry_task(self, task: Task):
        if task.attempts < task.max_retries:
            delay = task.backoff * (2 ** (task.attempts - 1))
            time.sleep(delay)
            self._enqueue_ready_task(task)
        else:
            task.status = TaskStatus.DEAD
            with self.lock:
                self.running_tasks.discard(task.id)

    def _save_state(self):
        state = {
            "tasks": {tid: task.to_dict() for tid, task in self.tasks.items()},
            "strategy": self.strategy.value,
            "max_workers": self.max_workers,
        }
        with open(self.state_path, "wb") as f:
            pickle.dump(state, f)

    def _load_state(self):
        if os.path.exists(self.state_path):
            with open(self.state_path, "rb") as f:
                state = pickle.load(f)
            self.strategy = ScheduleStrategy(state.get("strategy", self.strategy.value))
            self.max_workers = state.get("max_workers", self.max_workers)
            task_dicts = state.get("tasks", {})
            self.tasks = {}
            self.task_graph = defaultdict(set)
            self.reverse_graph = defaultdict(set)
            for tid, tdict in task_dicts.items():
                t = Task(
                    func=lambda: None,  # Placeholder; actual function restoration not supported here
                    dependencies=tdict["dependencies"],
                    priority=tdict["priority"],
                    timeout=tdict["timeout"],
                    name=tdict["id"],
                    max_retries=tdict["max_retries"],
                    backoff=tdict["backoff"],
                    est_runtime=tdict.get("est_runtime", 1.0)
                )
                t.status = TaskStatus(tdict["status"])
                t.attempts = tdict["attempts"]
                t.result = tdict["result"]
                t.exception = tdict["exception"]
                t.start_time = tdict["start_time"]
                t.end_time = tdict["end_time"]
                self.tasks[tid] = t
            for tid, task in self.tasks.items():
                for dep in task.dependencies:
                    self.task_graph[dep].add(tid)
                    self.reverse_graph[tid].add(dep)
            for tid, task in self.tasks.items():
                if not task.dependencies and task.status == TaskStatus.PENDING:
                    self._enqueue_ready_task(task)

    def _signal_handler(self, signum, frame):
        self.shutdown(graceful=True)
        exit(0)

    def shutdown(self, graceful=True):
        self.shutdown_flag.set()
        if graceful:
            self._save_state()
        self.executor.shutdown(wait=False)

    def report_progress(self):
        with self.lock:
            total = len(self.tasks)
            completed = sum(1 for t in self.tasks.values() if t.status == TaskStatus.SUCCESS)
            running = sum(1 for t in self.tasks.values() if t.status == TaskStatus.RUNNING)
            failed = sum(1 for t in self.tasks.values() if t.status == TaskStatus.FAILED)
            dead = sum(1 for t in self.tasks.values() if t.status == TaskStatus.DEAD)
            pending = total - completed - running - failed - dead
            percent = completed * 100.0 / total if total else 100.0
            eta = self._estimate_eta()
            print(f"[Progress] Total: {total}, Completed: {completed}, Running: {running}, Failed: {failed}, Dead: {dead}, Pending: {pending}, {percent:.2f}% complete, ETA: {eta}")

    def _estimate_eta(self) -> str:
        with self.eta_lock:
            completed_times = []
            for task in self.tasks.values():
                if task.status == TaskStatus.SUCCESS and task.start_time and task.end_time:
                    completed_times.append(task.end_time - task.start_time)
            if not completed_times:
                return "Unknown"
            avg_time = sum(completed_times) / len(completed_times)
            remaining = sum(1 for t in self.tasks.values() if t.status not in [TaskStatus.SUCCESS, TaskStatus.DEAD, TaskStatus.FAILED, TaskStatus.SKIPPED])
            est = remaining * avg_time / max(1, self.max_workers)
            return f"{est:.2f}s"

    def run(self):
        self._resolve_dependencies()
        futures = {}
        worker_lock = threading.Lock()
        shutdown_check = threading.Thread(target=self._watch_shutdown)
        shutdown_check.daemon = True
        shutdown_check.start()

        while True:
            self.report_progress()
            if self.shutdown_flag.is_set():
                break
            self._detect_dead_tasks()
            with self.lock:
                # Check if all tasks are complete
                if all(
                    t.status in [TaskStatus.SUCCESS, TaskStatus.DEAD, TaskStatus.FAILED, TaskStatus.SKIPPED]
                    for t in self.tasks.values()
                ):
                    break
            # Add newly ready tasks to ready queue
            with self.lock:
                for task in self._get_ready_tasks():
                    if task.id not in self.running_tasks and not any(e[1] == task.id for e in self.ready_queue):
                        self._enqueue_ready_task(task)
            # Launch available tasks
            while True:
                with self.lock:
                    if len(self.running_tasks) >= self.max_workers or not self.ready_queue:
                        break
                    _, tid = heapq.heappop(self.ready_queue)
                    task = self.tasks[tid]
                    if task.status != TaskStatus.PENDING:
                        continue
                    self.running_tasks.add(tid)
                    task.attempts += 1
                future = self.executor.submit(self._run_task_wrapper, task)
                with worker_lock:
                    futures[future] = task
            # Process completed tasks
            done = []
            for future in list(futures.keys()):
                if future.done():
                    done.append(future)
            for future in done:
                task = futures.pop(future)
                try:
                    future.result()
                except Exception:
                    pass  # handled in _run_task_wrapper
                with self.lock:
                    self.running_tasks.discard(task.id)
            time.sleep(0.5)
        self.report_progress()
        self._save_state()

    def _run_task_wrapper(self, task: Task):
        task.start_time = time.time()
        try:
            def timeout_target():
                try:
                    task.run()
                except Exception:
                    pass
            t = threading.Thread(target=timeout_target)
            t.start()
            t.join(timeout=task.timeout)
            if t.is_alive():
                # Timeout
                task.status = TaskStatus.DEAD
                raise TimeoutError(f"Task {task.id} timed out.")
            if task.status == TaskStatus.SUCCESS:
                return
            elif task.status == TaskStatus.FAILED:
                raise Exception(task.exception)
        except Exception as e:
            if task.attempts < task.max_retries:
                self._retry_task(task)
            else:
                task.status = TaskStatus.DEAD

    def _watch_shutdown(self):
        while not self.shutdown_flag.is_set():
            time.sleep(1)
        self.executor.shutdown(wait=False)
        self._save_state()

