import re
import unicodedata
import string
import math
from collections import Counter, defaultdict
from functools import lru_cache

try:
    from nltk.stem import PorterStemmer
except ImportError:
    PorterStemmer = None

try:
    import numpy as np
except ImportError:
    np = None

# ================== Tokenization ==================

def word_tokenize(text):
    text = str(text)
    # Basic word tokens, including contractions and hyphens
    pattern = r"\b\w[\w'-]*\b"
    return re.findall(pattern, text)

def sentence_tokenize(text):
    text = str(text)
    # Simple sentence tokenizer
    pattern = r'(?<=[.!?])\s+'
    sentences = re.split(pattern, text.strip())
    if sentences and sentences[-1] == '':
        sentences = sentences[:-1]
    return sentences

def regex_tokenize(text, pattern):
    text = str(text)
    return re.findall(pattern, text)

# ================== Normalization ==================

def lowercase(text):
    if not isinstance(text, str):
        return text
    return text.lower()

def unicode_normalize(text, form='NFKC'):
    if not isinstance(text, str):
        return text
    return unicodedata.normalize(form, text)

def whitespace_cleanup(text):
    if not isinstance(text, str):
        return text
    # Replaces multiple whitespaces/newlines/tabs with single space
    return re.sub(r'\s+', ' ', text).strip()

def stem_tokens(tokens):
    if PorterStemmer is not None:
        stemmer = PorterStemmer()
        return [stemmer.stem(token) for token in tokens]
    # fallback: simple suffix stripping
    return [re.sub(r'(ing|ed|ly|es|s)$', '', token) for token in tokens]

def normalize_text(
    text,
    lowercase_flag=True,
    unicode_flag=True,
    whitespace_flag=True
):
    if not text:
        return ''
    if unicode_flag:
        text = unicode_normalize(text)
    if lowercase_flag:
        text = lowercase(text)
    if whitespace_flag:
        text = whitespace_cleanup(text)
    return text

# ================== N-gram Extraction ==================

def ngram(tokens, n):
    return [tuple(tokens[i:i + n]) for i in range(len(tokens) - n + 1)]

def ngram_frequencies(tokens, n):
    grams = ngram(tokens, n)
    freq = Counter(grams)
    return freq

# ================== Similarity Functions ==================

def jaccard_similarity(a_tokens, b_tokens):
    set_a = set(a_tokens)
    set_b = set(b_tokens)
    if not set_a and not set_b:
        return 1.0
    if not set_a or not set_b:
        return 0.0
    return len(set_a & set_b) / len(set_a | set_b)

def cosine_similarity(a_tokens, b_tokens):
    if not a_tokens and not b_tokens:
        return 1.0
    if not a_tokens or not b_tokens:
        return 0.0
    vec_a = Counter(a_tokens)
    vec_b = Counter(b_tokens)
    all_items = set(vec_a) | set(vec_b)
    dot = sum(vec_a[k] * vec_b[k] for k in all_items)
    norm_a = math.sqrt(sum(v**2 for v in vec_a.values()))
    norm_b = math.sqrt(sum(v**2 for v in vec_b.values()))
    if norm_a == 0 or norm_b == 0:
        return 0.0
    return dot / (norm_a * norm_b)

@lru_cache(maxsize=1024)
def levenshtein_distance(a, b):
    if a == b: return 0
    if not a: return len(b)
    if not b: return len(a)
    previous_row = range(len(b) + 1)
    for i, ca in enumerate(a):
        current_row = [i + 1]
        for j, cb in enumerate(b):
            insertions = previous_row[j + 1] + 1
            deletions = current_row[j] + 1
            substitutions = previous_row[j] + (ca != cb)
            current_row.append(min(insertions, deletions, substitutions))
        previous_row = current_row
    return previous_row[-1]

def normalized_levenshtein_similarity(a, b):
    if not a and not b: 
        return 1.0
    dist = levenshtein_distance(a, b)
    return 1.0 - dist / max(len(a), len(b), 1)

# ================== TF-IDF & Keyword Extraction ==================

class TfIdfVectorizer:
    def __init__(self):
        self.df = defaultdict(int)
        self.idf = {}
        self.vocabulary_ = {}
        self.N = 0

    def fit(self, documents):
        self.N = len(documents)
        for doc in documents:
            tokens = set(word_tokenize(doc))
            for token in tokens:
                self.df[token] += 1
        self.vocabulary_ = {token: i for i, token in enumerate(self.df)}
        for token, df in self.df.items():
            self.idf[token] = math.log((1 + self.N) / (1 + df)) + 1

    def transform(self, document):
        tokens = word_tokenize(document)
        tf = Counter(tokens)
        tfidf = {}
        for token in tf:
            if token in self.idf:
                tfidf[token] = tf[token] * self.idf[token]
        return tfidf

    def fit_transform(self, documents):
        self.fit(documents)
        return [self.transform(doc) for doc in documents]

def extract_keywords(text, corpus=None, top_n=10):
    if not text:
        return []
    if not corpus:
        corpus = [text]
    vectorizer = TfIdfVectorizer()
    vectorizer.fit(corpus)
    tfidf = vectorizer.transform(text)
    return [k for k, _ in sorted(tfidf.items(), key=lambda x: -x[1])[:top_n]]

# ================== Text Summarization ==================

def sentence_scores(text, corpus=None):
    # Score sentences by TF-IDF of their words
    sents = sentence_tokenize(text)
    if not sents:
        return []
    if not corpus:
        corpus = [text]
    vectorizer = TfIdfVectorizer()
    vectorizer.fit(corpus)
    sent_scores = []
    for sent in sents:
        tfidf = vectorizer.transform(sent)
        score = sum(tfidf.values())
        sent_scores.append((sent, score))
    return sent_scores

def summarize(text, corpus=None, top_n=3):
    if not text:
        return ''
    scores = sentence_scores(text, corpus)
    if not scores:
        return ''
    # Pick top_n sentences by score, preserve order
    top_sents = sorted(scores, key=lambda x: -x[1])[:top_n]
    sent_set = set(s for s, _ in top_sents)
    sents = sentence_tokenize(text)
    summary = [s for s in sents if s in sent_set]
    return ' '.join(summary)

# ================== Language Detection Heuristics ==================

LANGUAGE_PROFILES = {
    'en': {'the', 'and', 'of', 'to', 'a', 'in', 'that', 'is'},
    'fr': {'le', 'de', 'et', 'la', 'les', 'des', 'en', 'un', 'du', 'est'},
    'es': {'el', 'la', 'de', 'que', 'y', 'en', 'los', 'del', 'se', 'las'},
    'de': {'der', 'die', 'und', 'in', 'zu', 'den', 'das', 'nicht', 'von', 'sie'},
    'it': {'di', 'e', 'il', 'la', 'che', 'in', 'le', 'del', 'un', 'per'}
    # Extend as needed...
}

def detect_language(text):
    if not text:
        return None
    words = set(word_tokenize(lowercase(text)))
    scores = {}
    for lang, keywords in LANGUAGE_PROFILES.items():
        scores[lang] = len(words & keywords)
    best = sorted(scores.items(), key=lambda x: -x[1])
    if not best or best[0][1] == 0:
        return 'unknown'
    return best[0][0]

# ================== Pipeline ==================

def text_processing_pipeline(
    text,
    steps=(
        'normalize',
        'tokenize',
        'stem',
        'ngram',
        'keywords',
    ),
    ngram_n=2,
    corpus=None,
    top_n=5,
    regex_pattern=None,
):
    """
    Steps can include: 'normalize', 'tokenize', 'regex_tokenize', 'stem', 'ngram', 'keywords', 'summarize', etc.
    """
    result = text
    tokens = None
    output = {}
    for step in steps:
        if step == 'normalize':
            result = normalize_text(result)
            output['normalized'] = result
        elif step == 'tokenize':
            tokens = word_tokenize(result)
            output['tokens'] = tokens
        elif step == 'sentence_tokenize':
            sents = sentence_tokenize(result)
            output['sentences'] = sents
        elif step == 'regex_tokenize' and regex_pattern:
            tokens = regex_tokenize(result, regex_pattern)
            output['regex_tokens'] = tokens
        elif step == 'stem':
            if tokens is None:
                tokens = word_tokenize(result)
            stemmed = stem_tokens(tokens)
            tokens = stemmed
            output['stemmed_tokens'] = tokens
        elif step == 'ngram':
            if tokens is None:
                tokens = word_tokenize(result)
            grams = ngram(tokens, ngram_n)
            output['ngrams'] = grams
            output['ngram_freq'] = ngram_frequencies(tokens, ngram_n)
        elif step == 'keywords':
            kw = extract_keywords(result, corpus=corpus, top_n=top_n)
            output['keywords'] = kw
        elif step == 'summarize':
            summary = summarize(result, corpus=corpus, top_n=top_n)
            output['summary'] = summary
        elif step == 'language':
            lang = detect_language(result)
            output['language'] = lang
    return output

# ================== Utility Functions ==================

def handle_encoding(text):
    """Safely decode bytes to str if necessary."""
    if isinstance(text, bytes):
        try:
            return text.decode('utf-8')
        except UnicodeDecodeError:
            return text.decode('latin1', errors='replace')
    return str(text)

def safe_truncate(text, max_length=1000000):
    """Truncate very long texts confidently."""
    if not isinstance(text, str):
        text = handle_encoding(text)
    if len(text) > max_length:
        return text[:max_length]
    return text

import threading
from copy import deepcopy
import operator

class Column:
    def __init__(self, name, col_type, primary_key=False, not_null=False, unique=False, auto_increment=False, default=None):
        self.name = name
        self.type = col_type
        self.primary_key = primary_key
        self.not_null = not_null or primary_key
        self.unique = unique or primary_key
        self.auto_increment = auto_increment or primary_key
        self.default = default

class ConstraintError(Exception):
    pass

class TypeMismatchError(Exception):
    pass

class ColumnNotFoundError(Exception):
    pass

class Index:
    def __init__(self, table, column_name):
        self.table = table
        self.column = column_name
        self._build_index()

    def _build_index(self):
        self.index = {}
        for i, row in enumerate(self.table._rows):
            value = row[self.column]
            if value not in self.index:
                self.index[value] = []
            self.index[value].append(i)

    def update_on_insert(self, row, idx):
        value = row[self.column]
        if value not in self.index:
            self.index[value] = []
        self.index[value].append(idx)

    def update_on_delete(self, idx, value):
        if value in self.index and idx in self.index[value]:
            self.index[value].remove(idx)
            if not self.index[value]:
                del self.index[value]

    def lookup(self, value):
        if value in self.index:
            return [self.table._rows[i] for i in self.index[value]]
        return []

class Transaction:
    def __init__(self, table):
        self.original_rows = deepcopy(table._rows)
        self.table = table

    def rollback(self):
        self.table._rows = deepcopy(self.original_rows)
        self.table._rebuild_indexes()

    def commit(self):
        self.original_rows = deepcopy(self.table._rows)

class Table:
    _type_map = {
        int: int,
        float: float,
        str: str,
        bool: bool,
    }
    _aggregate_funcs = {
        'COUNT': lambda values: len(values),
        'SUM': lambda values: sum(v for v in values if v is not None),
        'AVG': lambda values: sum(v for v in values if v is not None)/len([v for v in values if v is not None]) if len([v for v in values if v is not None]) > 0 else None,
        'MIN': lambda values: min((v for v in values if v is not None), default=None),
        'MAX': lambda values: max((v for v in values if v is not None), default=None),
    }
    _lock = threading.RLock()

    def __init__(self, name, columns):
        self.name = name
        self.columns = {col.name: col for col in columns}
        self._rows = []
        self._indexes = {}
        self._auto_increment_counters = {}
        self._primary_keys = [col.name for col in columns if col.primary_key]
        for col in columns:
            if col.auto_increment:
                self._auto_increment_counters[col.name] = 1
        self._transaction = None

    def create_index(self, column_name):
        if column_name not in self.columns:
            raise ColumnNotFoundError(f"Column {column_name} does not exist")
        idx = Index(self, column_name)
        self._indexes[column_name] = idx

    def _rebuild_indexes(self):
        for col, idx in self._indexes.items():
            idx._build_index()

    def begin(self):
        with self._lock:
            if self._transaction is None:
                self._transaction = Transaction(self)
            else:
                raise Exception("Transaction already open.")

    def commit(self):
        with self._lock:
            if self._transaction is not None:
                self._transaction.commit()
                self._transaction = None
            else:
                raise Exception("No open transaction.")

    def rollback(self):
        with self._lock:
            if self._transaction is not None:
                self._transaction.rollback()
                self._transaction = None
            else:
                raise Exception("No open transaction.")

    def insert(self, data):
        with self._lock:
            row = {}
            for col_name, col in self.columns.items():
                if col_name in data:
                    value = data[col_name]
                elif col.auto_increment:
                    value = self._auto_increment_counters[col_name]
                elif col.default is not None:
                    value = col.default
                else:
                    value = None

                if value is None and col.not_null:
                    raise ConstraintError(f"Column {col_name} cannot be NULL")

                if value is not None and not isinstance(value, col.type):
                    try:
                        value = self._type_map[col.type](value)
                    except Exception:
                        raise TypeMismatchError(f"Type mismatch on column {col_name} ({value} is not {col.type})")

                row[col_name] = value

            for col_name, col in self.columns.items():
                if col.unique:
                    for r in self._rows:
                        if r[col_name] == row[col_name]:
                            raise ConstraintError(f"Unique constraint violation on {col_name}")

            self._rows.append(row)
            idx = len(self._rows)-1
            # Index auto update
            for col, index in self._indexes.items():
                index.update_on_insert(row, idx)
            # Increase auto_increment
            for col_name in self._auto_increment_counters:
                if row[col_name] >= self._auto_increment_counters[col_name]:
                    self._auto_increment_counters[col_name] = row[col_name]+1

            return deepcopy(row)

    def _eval_condition(self, row, cond):
        # cond is parsed as nested tuple: ("col", "op", value) or ('AND', left, right) or ('OR', left, right)
        if isinstance(cond, tuple):
            if cond[0] in ('AND', 'OR'):
                op = cond[0]
                left = self._eval_condition(row, cond[1])
                right = self._eval_condition(row, cond[2])
                return (left and right) if op == 'AND' else (left or right)
            else:
                col, op_, val = cond
                if col not in self.columns:
                    raise ColumnNotFoundError(f"{col} not in table")
                cell = row[col]
                opmap = {'=': operator.eq, '!=': operator.ne, '>': operator.gt, '<': operator.lt,
                         '>=': operator.ge, '<=': operator.le}
                if op_ not in opmap:
                    raise Exception(f'Unsupported operator {op_}')
                return opmap[op_](cell, val)
        elif isinstance(cond, bool):
            return cond
        else:
            raise Exception('Invalid WHERE clause structure')

    def _filter(self, rows, where):
        if where is None:
            return rows
        return [row for row in rows if self._eval_condition(row, where)]

    def select(self, columns=None, where=None, order_by=None, group_by=None, aggregates=None, join=None, limit=None):
        with self._lock:
            rows = deepcopy(self._rows)
            if join:
                rows = self._join(rows, join)

            if where:
                rows = self._filter(rows, where)

            if group_by:
                grouped = {}
                for row in rows:
                    group_key = tuple(row[col] for col in group_by)
                    grouped.setdefault(group_key, []).append(row)
                result = []
                for group_key, members in grouped.items():
                    grouprow = {}
                    if columns:
                        for col in columns:
                            grouprow[col] = members[0][col]
                    else:
                        grouprow = members[0].copy()
                    if aggregates:
                        for agg_func, agg_col, as_name in aggregates:
                            vals = [row[agg_col] for row in members]
                            grouprow[as_name] = self._aggregate_funcs[agg_func](vals)
                    result.append(grouprow)
                rows = result
            elif aggregates:
                grouprow = {}
                for agg_func, agg_col, as_name in aggregates:
                    vals = [row[agg_col] for row in rows]
                    grouprow[as_name] = self._aggregate_funcs[agg_func](vals)
                rows = [grouprow]

            if columns:
                filtered_rows = []
                for r in rows:
                    filtered_rows.append({col: r[col] for col in columns if col in r})
                rows = filtered_rows

            if order_by:
                def sort_key(row):
                    return tuple(row[coln] for coln,rev in order_by)
                for coln, rev in reversed(order_by):
                    rows.sort(key=lambda row: row[coln], reverse=rev)

            if limit is not None:
                rows = rows[:limit]
            return deepcopy(rows)

    def update(self, data, where=None):
        with self._lock:
            rows = self._rows
            updated = 0
            for idx, row in enumerate(rows):
                if where is None or self._eval_condition(row, where):
                    for col_name, value in data.items():
                        if col_name not in self.columns:
                            raise ColumnNotFoundError(f"{col_name} not in table")
                        col = self.columns[col_name]
                        if value is None and col.not_null:
                            raise ConstraintError(f"Column {col_name} cannot be NULL")
                        if value is not None and not isinstance(value, col.type):
                            try:
                                value = self._type_map[col.type](value)
                            except Exception:
                                raise TypeMismatchError(f"Type mismatch on {col_name}")
                        if col.unique:
                            for i, r in enumerate(self._rows):
                                if i != idx and r[col_name] == value:
                                    raise ConstraintError(f"Unique constraint violation on {col_name}")
                        old_val = row[col_name]
                        row[col_name] = value
                        # index update
                        if col_name in self._indexes:
                            self._indexes[col_name].update_on_delete(idx, old_val)
                            self._indexes[col_name].update_on_insert(row, idx)
                    updated += 1
            return updated

    def delete(self, where=None):
        with self._lock:
            new_rows = []
            deleted = 0
            for idx, row in enumerate(self._rows):
                if where is None or self._eval_condition(row, where):
                    for col, idxobj in self._indexes.items():
                        idxobj.update_on_delete(idx, row[col])
                    deleted += 1
                else:
                    new_rows.append(row)
            self._rows = new_rows
            self._rebuild_indexes()
            return deleted

    def _join(self, left_rows, join_info):
        # join_info: {'type':'inner'|'left'|'right', 'table':Table, 'on': ('selfcol','othercol')}
        join_type = join_info['type']
        right_table = join_info['table']
        left_col, right_col = join_info['on']

        result = []
        right_rows = deepcopy(right_table._rows)

        if join_type == 'inner':
            for lrow in left_rows:
                match = False
                for rrow in right_rows:
                    if lrow[left_col] == rrow[right_col]:
                        joined = lrow.copy()
                        for k,v in rrow.items():
                            joined[f"{right_table.name}.{k}"] = v
                        result.append(joined)
                        match = True
            return result
        elif join_type == 'left':
            for lrow in left_rows:
                matched = False
                for rrow in right_rows:
                    if lrow[left_col] == rrow[right_col]:
                        joined = lrow.copy()
                        for k,v in rrow.items():
                            joined[f"{right_table.name}.{k}"] = v
                        result.append(joined)
                        matched = True
                if not matched:
                    joined = lrow.copy()
                    for k in right_table.columns:
                        joined[f"{right_table.name}.{k}"] = None
                    result.append(joined)
            return result
        elif join_type == 'right':
            for rrow in right_rows:
                matched = False
                for lrow in left_rows:
                    if lrow[left_col] == rrow[right_col]:
                        joined = lrow.copy()
                        for k,v in rrow.items():
                            joined[f"{right_table.name}.{k}"] = v
                        result.append(joined)
                        matched = True
                if not matched:
                    joined = {}
                    for k in left_rows[0].keys():
                        joined[k] = None
                    for k,v in rrow.items():
                        joined[f"{right_table.name}.{k}"] = v
                    result.append(joined)
            return result
        else:
            raise Exception(f"Unsupported JOIN type: {join_type}")
